function ensureNpmrcForCI() {
  if (!exists(NPMRC)) return;
  const content = fs.readFileSync(NPMRC, 'utf8');
  if (/package-lock\s*=\s*false/i.test(content)) {
    console.error('ERROR: .npmrc disables package-lock (package-lock=false). Remove it to ensure reproducible builds.');
    process.exit(1);
  }
}

